public static server str getTermsOfPayment()
{
    return SysComputedColumn::returnField(
        tableStr(LedgerJournalEntity),
        dataEntityDataSourceStr(LedgerJournalEntity, LedgerJournalTrans),
        fieldStr(LedgerJournalTrans, Payment));
}

protected static int64 createJournalLines(
    DMFDefinitionGroupExecution _dmfDefinitionGroupExecution,
    DimensionDataEntitySFKCacheTmp _dimCacheTmp,
    DimensionDataEntitySFKCacheTmp _dimCacheTmpRef,
    DimensionDataEntitySFKCacheTmp _defaultDimCacheTmp,
    DimensionDataEntitySFKCacheTmp _defaultDimCacheTmpRef,
    boolean _delayTaxCalculation)
{
    // 1. Let the standard Microsoft logic create the lines first
    int64 ret = next createJournalLines(_dmfDefinitionGroupExecution, _dimCacheTmp, _dimCacheTmpRef, _defaultDimCacheTmp, _defaultDimCacheTmpRef, _delayTaxCalculation);

    LedgerJournalTrans ledgerJournalTrans;
    LedgerJournalEntityStaging staging;

    // 2. Bulk update the newly created lines with your unmapped field from the staging table
    update_recordset ledgerJournalTrans
        setting Payment = staging.TermsOfPayment
    join staging
        where staging.JournalBatchNumber == ledgerJournalTrans.JournalNum
           && staging.LineNumber == ledgerJournalTrans.LineNum
           && staging.DefinitionGroup == _dmfDefinitionGroupExecution.DefinitionGroup
           && staging.ExecutionId == _dmfDefinitionGroupExecution.ExecutionId
           && staging.TransferStatus == DMFTransferStatus::NotStarted;

    return ret;
}

protected static int64 updateExistingJournalLines(
    DMFDefinitionGroupExecution _dmfDefinitionGroupExecution,
    DimensionDataEntitySFKCacheTmp _dimCacheTmp,
    DimensionDataEntitySFKCacheTmp _dimCacheTmpRef,
    DimensionDataEntitySFKCacheTmp _defaultDimCacheTmp,
    DimensionDataEntitySFKCacheTmp _defaultDimCacheTmpRef,
    boolean _delayTaxCalculation)
{
    // 1. Let the standard Microsoft logic update the lines first
    int64 ret = next updateExistingJournalLines(_dmfDefinitionGroupExecution, _dimCacheTmp, _dimCacheTmpRef, _defaultDimCacheTmp, _defaultDimCacheTmpRef, _delayTaxCalculation);

    LedgerJournalTrans ledgerJournalTrans;
    LedgerJournalEntityStaging staging;

    // 2. Bulk update the existing lines with your unmapped field from the staging table
    update_recordset ledgerJournalTrans
        setting Payment = staging.TermsOfPayment
    join staging
        where staging.JournalBatchNumber == ledgerJournalTrans.JournalNum
           && staging.LineNumber == ledgerJournalTrans.LineNum
           && staging.DefinitionGroup == _dmfDefinitionGroupExecution.DefinitionGroup
           && staging.ExecutionId == _dmfDefinitionGroupExecution.ExecutionId
           && staging.TransferStatus == DMFTransferStatus::NotStarted;

    return ret;
}
